def find(q):
    q = q.lower().strip()
    return [(c,n) for c,n in specialties if q in c.lower() or q in n.lower()]

def chance(score, risk, support=False):
    adjusted = score * 1.02 if support else score
    diff = adjusted - risk
    if diff >= 8: return 'дуже реально'
    if diff >= 0: return 'реально'
    if diff >= -6: return 'сміливо'
    return 'ризик'

def main():
    print('Підбір спеціальності ЛНТУ / ЄДЕБО-стиль')
    score_raw = input('Твій бал [154.5]: ').strip()
    score = float(score_raw.replace(',', '.') or 154.5)
    query = input('Введи код або назву спеціальності, або Enter для топу: ').strip()
    if query:
        pool = find(query)
        if not pool:
            print('Нічого не знайдено.')
            return
    else:
        top_codes = ['F6','F7','F5','F3','F2','D3','D5','A5.39','A4.09','J8','G7','G3','G19','K10','E2','H1']
        pool = [(c,n) for c,n in specialties if c in top_codes]
    ranked = []
    for c,n in pool:
        r = recommendations.get(c, {'risk':150,'support':False,'note':'Перевір конкурсну пропозицію в ЄДЕБО.', 'demand':6})
        status = chance(score, r.get('risk',150), r.get('support', False))
        ranked.append((r.get('demand',6), c, n, status, r.get('note','')))
    ranked.sort(reverse=True)
    print('\nРезультат:')
    for i, (_, c, n, status, note) in enumerate(ranked[:20], 1):
        print(f'{i}. {c} {n} — {status}')
        if note: print(f'   {note}')

if __name__ == '__main__':
    main()
